function clear_MODULO() 
{ 
clear_banco();
clear_sucursal();
}

function refresh_MODULO() 
{ 
refresh_banco();
refresh_sucursal();
}

function addWhere_MODULO() 
{                    

//Comienzo
var where = "";
var sep = "";  
var aux = "";

//Listas
aux = addWhere_banco();    if (aux) { where+=sep+aux; sep=" AND "; }
aux = addWhere_sucursal(); if (aux) { where+=sep+aux; sep=" AND "; }	

return where; 
}




function delete_banco() { deleteItem("banco"); }
function delete_sucursal() { deleteItem("sucursal"); }

function clear_banco() { clear("banco"); }
function clear_sucursal() { clear("sucursal"); }

function refresh_banco() { refresh("banco"); }
function refresh_sucursal() { refresh("sucursal"); }

function add_banco() { add("banco", "NucleusRH.Base.Liquidacion.Bancos.BANCO.check.flow"); }
function add_sucursal() { add("sucursal", "NucleusRH.Base.Liquidacion.Bancos.SUCURSAL.check.flow"); }

function addWhere_banco() { return addWhere2("banco", "LIQ.oi_sucursal", "LIQ22_BANCOS_SUCUR", "oi_sucursal", "oi_banco"); } 
function addWhere_sucursal() { return addWhere("sucursal", "LIQ.oi_sucursal"); }
